const response = $input.item.json;
const statusCode = response.statusCode || 0;

if (statusCode !== 200) {
  return {
    api_status: statusCode,
    products_found: 0,
    products_with_price: 0,
    has_add_to_cart: false,
    verdict: 'NO - API not accessible (status ' + statusCode + ')',
    passed: false
  };
}

// n8n puts the response body in 'body' when includeResponseHeaders is ON
let products = [];
try {
  const raw = response.body;
  if (Array.isArray(raw)) {
    products = raw;
  } else if (typeof raw === 'string') {
    products = JSON.parse(raw);
  } else if (raw && typeof raw === 'object' && raw.id) {
    // Single product returned
    products = [raw];
  }
} catch(e) {
  products = [];
}

if (products.length === 0) {
  return {
    api_status: statusCode,
    products_found: 0,
    products_with_price: 0,
    has_add_to_cart: false,
    verdict: 'NO - Could not parse products from API',
    passed: false
  };
}

// Count products with real price > 0
const withPrice = products.filter(p => {
  const price = parseFloat(p.prices?.price || 0);
  const regular = parseFloat(p.prices?.regular_price || 0);
  return price > 0 || regular > 0;
});

// Check for "Add to cart" button text
const hasAddToCart = products.some(p => {
  const cartText = (p.add_to_cart?.text || '').toLowerCase();
  return cartText === 'add to cart';
});

// Check for price range (variable products)
const hasPriceRange = products.some(p => p.prices?.price_range !== null && p.prices?.price_range !== undefined);

const isRealStore = withPrice.length > 0 || hasAddToCart || hasPriceRange;

return {
  api_status: statusCode,
  products_found: products.length,
  products_with_price: withPrice.length,
  has_add_to_cart: hasAddToCart,
  has_price_range: hasPriceRange,
  verdict: isRealStore 
    ? 'YES - Real ecommerce (' + withPrice.length + ' products with price)' 
    : 'NO - No purchasable products found',
  passed: isRealStore
};

const response = $input.item.json;
const html = (response.body || response.data || '').toString();
const lower = html.toLowerCase();

const hasWooClass =
  html.includes('woocommerce-cart') ||
  html.includes('woocommerce-checkout') ||
  lower.includes('class="woocommerce') ||
  lower.includes("class='woocommerce") ||
  html.includes('wc-cart') ||
  html.includes('woocommerce_cart_nonce');

return {
  cart_status: response.statusCode || 0,
  cart_has_woo: hasWooClass,
};

const response = $input.item.json;
const html = (response.body || response.data || '').toString();
const lower = html.toLowerCase();

const signals = {
  add_to_cart_btn:  html.includes('add_to_cart_button'),
  woo_price:        html.includes('woocommerce-Price-amount'),
  woo_body_class:   lower.includes('class="woocommerce') || lower.includes("class='woocommerce"),
  woo_product_link: lower.includes('/product/') || lower.includes('?add-to-cart='),
  woo_loop:         html.includes('woocommerce-loop') || html.includes('products columns'),
  woo_notices:      html.includes('woocommerce-notices-wrapper'),
};

const score = Object.values(signals).filter(Boolean).length;
return {
  homepage_score: score,
  homepage_signals: JSON.stringify(signals),
  homepage_passed: score >= 2,
};
